content:
Extension of `jet.config.yaml` with a `css` section (see `jit-runner.md` for base `JetConfig` schema):

```json
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "jet://schemas/jet-config-css-extension",
  "description": "jet.config.yaml 'css' section — extends JetConfig with Tailwind pipeline options",
  "type": "object",
  "properties": {
    "css": {
      "type": "object",
      "properties": {
        "entry": {
          "type": "string",
          "description": "CSS entry point relative to project root (e.g. 'src/index.css')"
        },
        "tailwind": {
          "type": "object",
          "description": "Inline Tailwind config (alternative to tailwind.config.js)",
          "properties": {
            "content": {
              "type": "array",
              "items": { "type": "string" },
              "description": "Content glob patterns"
            },
            "darkMode": {
              "enum": ["class"],
              "description": "Dark mode strategy"
            },
            "theme": {
              "type": "object",
              "properties": {
                "extend": { "type": "object" }
              }
            },
            "plugins": {
              "type": "array",
              "items": { "type": "string" },
              "description": "Plugin names: tailwindcss-animate, @tailwindcss/typography"
            }
          }
        },
        "modules": {
          "type": "boolean",
          "default": false,
          "description": "Enable CSS Modules for .module.css imports"
        }
      }
    }
  }
}
```

#### Example jet.config.yaml

```yaml
css:
  entry: src/index.css
  tailwind:
    content:
      - ./src/**/*.{ts,tsx}
    darkMode: class
    theme:
      extend:
        colors:
          primary: hsl(var(--primary))
          primary-foreground: hsl(var(--primary-foreground))
    plugins:
      - tailwindcss-animate
      - "@tailwindcss/typography"
```

#### Config Resolution Priority

| Source | Priority | Notes |
|--------|----------|-------|
| `tailwind.config.js` | 1 (highest) | Parsed via JS object literal evaluator |
| `jet.config.yaml` `css.tailwind` | 2 | YAML-native config |
| Built-in defaults | 3 (lowest) | Preflight on, no plugins, no dark mode |
